                    // Rozli\u0161en\xed tisku\n    "completeLabelSettings": {\n      "isCompleteLabelRequested": true,  // Po\u017eadavek na kompletn\xed \u0161t\xedtek\n      "pageSize": "A4",                  // Velikost pap\xedru\n      "position": 1                      // Pozice na str\xe1nce\n    }\n  },\n  "shipments": [\n    {\n      "referenceId": "Reference03",      // Hlavn\xed z\xe1kaznick\xe1 reference z\xe1silky\n      "productType": "CONN",             // Typ produktu (CONN = Slovensko)\n      "note": "Poznamka",                // Pozn\xe1mka ke v\u0161em z\xe1silk\xe1m\n      "integratorId": "422609",          // ID integr\xe1tora\n      \n      // === KL\xcd\u010cOV\xc1 \u010c\xc1ST PRO KONVERZI ===\n      // Definice sady z\xe1silek s individu\xe1ln\xedmi v\xe1hami a extern\xedmi \u010d\xedsly pro ka\u017edou z\xe1silku\n      "shipmentSet": {\n        "numberOfShipments": 3,          // Po\u010det z\xe1silek v sad\u011b\n        "shipmentSetItems": [\n          {\n            "weighedShipmentInfo": {     // Prvn\xed z\xe1silka s vlastn\xed v\xe1hou\n              "weight": 1.5              // V\xe1ha 1.5 kg\n            },\n            "externalNumbers": [         // Extern\xed \u010d\xedsla specifick\xe1 pro PRVN\xcd z\xe1silku v sad\u011b\n              { \n                "externalNumber": "Ext_Box1_CUST", \n                "code": "CUST"           // Z\xe1kaznick\xe9 \u010d\xedslo pro prvn\xed z\xe1silku\n              }\n            ]\n          },\n          {\n            "weighedShipmentInfo": {     // Druh\xe1 z\xe1silka s vlastn\xed v\xe1hou\n              "weight": 3.2              // V\xe1ha 3.2 kg\n            },\n            "externalNumbers": [         // Extern\xed \u010d\xedsla specifick\xe1 pro DRUHOU z\xe1silku v sad\u011b\n              { \n                "externalNumber": "Ext_Box2_CUST", \n                "code": "CUST"           // Z\xe1kaznick\xe9 \u010d\xedslo pro druhou z\xe1silku  \n              },\n              { \n                "externalNumber": "B2CO_000222", \n                "code": "B2CO"           // B2C \u010d\xedslo pro druhou z\xe1silku\n              }\n            ]\n          },\n          {\n            "weighedShipmentInfo": {     // T\u0159et\xed z\xe1silka s vlastn\xed v\xe1hou\n              "weight": 5.8              // V\xe1ha 5.8 kg\n            },\n            "externalNumbers": [         // Extern\xed \u010d\xedsla specifick\xe1 pro T\u0158ET\xcd z\xe1silku v sad\u011b\n              { \n                "externalNumber": "Ext_Box3_CUST", \n                "code": "CUST"           // Z\xe1kaznick\xe9 \u010d\xedslo pro t\u0159et\xed z\xe1silku\n              },\n              { \n                "externalNumber": "B2CO_000333", \n                "code": "B2CO"           // B2C \u010d\xedslo pro t\u0159et\xed z\xe1silku\n              },\n              { \n                "externalNumber": "ESHOP_999", \n                "code": "VARS"           // \u010c\xedslo varianty pro t\u0159et\xed z\xe1silku (k\xf3d VARS z \u010d\xedseln\xedku)\n              }\n            ]\n          }\n        ]\n      },\n      // === KONEC KL\xcd\u010cOV\xc9 \u010c\xc1STI ===\n      \n      // \xdadaje o odes\xedlateli - spole\u010dn\xe9 pro v\u0161echny z\xe1silky\n      "sender": {\n        "name": "Name sender",\n        "street": "Street sender 99",\n        "city": "Olomouc",\n        "zipCode": "77200",\n        "country": "CZ",\n        "contact": "Contact sender",\n        "phone": "+420777999888",\n        "email": "test@test.cz"\n      },\n      \n      // \xdadaje o p\u0159\xedjemci - spole\u010dn\xe9 pro v\u0161echny z\xe1silky\n      "recipient": {\n        "name": "Recipient Gunter",\n        "street": "Janosika 22",\n        "city": "Zilina",\n        "zipCode": "01001",\n        "country": "SK",\n        "contact": "Recipient Kontakte",\n        "phone": "+49777888999",\n        "email": "recipient@example.sk"\n      },\n      \n      // Poji\u0161t\u011bn\xed z\xe1silky\n      "insurance": {\n        "insurancePrice": "156000",\n        "insuranceCurrency": "CZK"\n      },\n      \n      // \xdadaje pro zp\u011btn\xe9 doru\u010den\xed\n      "dormant": {\n        "note": "Poznamka return",\n        "depot": "07",\n        "recipient": {\n          "name": "Name return",\n          "street": "Street return 99",\n          "city": "Olomouc",\n          "zipCode": "77200",\n          "country": "CZ",\n          "contact": "Contact return",\n          "phone": "+420777999888",\n          "email": "test@test.cz"\n        },\n        "services": [\n          {\n            "code": "PUBC"               // Slu\u017eba pro zp\u011btn\xe9 doru\u010den\xed\n          }\n        ]\n      }\n    }\n  ]\n}',complexity:"complex",category:"Z\xe1silky"}],faqItems:[{id:"auth-how",question:"Jak se p\u0159ihl\xe1sit k API?",answer:"Pro p\u0159ihl\xe1\u0161en\xed k CPL API je pot\u0159eba pou\u017e\xedt OAuth2 autentizaci. Vol\xe1n\xed prob\xedh\xe1 pomoc\xed client_id a client_secret, kter\xe9 z\xedsk\xe1te od PPL. Autentizace se prov\xe1d\xed na endpointu /login/getAccessToken a vr\xe1t\xed v\xe1m JWT token, kter\xfd n\xe1sledn\u011b pou\u017e\xedv\xe1te v hlavi\u010dce Authorization: Bearer {token} pro v\u0161echna dal\u0161\xed API vol\xe1n\xed.",category:"Autentizace"},{id:"shipment-create",question:"Jak vytvo\u0159it z\xe1silku?",answer:"Pro vytvo\u0159en\xed z\xe1silky pou\u017eijte metodu POST na endpoint /shipment/batch. V po\u017eadavku mus\xedte specifikovat informace o odes\xedlateli, p\u0159\xedjemci, typu produktu, po\u010dtu bal\xedk\u016f a dal\u0161\xedch parametrech z\xe1silky. Po \xfasp\u011b\u0161n\xe9m vytvo\u0159en\xed z\xedsk\xe1te identifik\xe1tor d\xe1vky, pomoc\xed kter\xe9ho m\u016f\u017eete st\xe1hnout \u0161t\xedtky nebo zjistit stav importu z\xe1silky.",category:"Z\xe1silky"}]},C=()=>{const[e,t]=(0,r.useState)(null),[n,a]=(0,r.useState)(null),[i,s]=(0,r.useState)(""),[u,c]=(0,r.useState)("endpoints"),[d,p]=(0,r.